import { createContext, useContext, useState, useEffect } from 'react';
import { HTMLHuelNotificationElement } from 'huel-notification';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

interface NotificationContextInterface {
  notification: HTMLHuelNotificationElement | null;
  notify: (props: NotificationProps) => Promise<void>;
}

const NotificationContext = createContext<NotificationContextInterface | null>(null);

const useNotification = () => {
  const notification = useContext(NotificationContext);
  const [notificationElement, setNotificationElement] = useState<HTMLHuelNotificationElement | null>(null);

  useEffect(() => {
    if (notification) {
      setNotificationElement(notification);
    }
  }, [notification]);

  const notify = async (props: NotificationProps) => {
    if (!notificationElement) return;

    const { heading, subheading, type } = props;
    await notificationElement.open({
      heading,
      subheading,
      type,
    });
  };

  return { notificationElement, notify };
};

export { NotificationContext, useNotification };
